# Try to find Bitwarden pricing from their open source code - look for pricing constants
curl -sL "https://api.github.com/repos/bitwarden/clients/git/trees/main?recursive=1" 2>/dev/null | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    # Look for pricing-related files
    for item in data.get('tree', []):
        path = item.get('path', '')
        if 'price' in path.lower() or 'billing' in path.lower() or 'subscription' in path.lower():
            print(path)
except Exception as e:
    print(f'Error: {e}')
"

